"""
Customer management service.
Handles customer registration, lookup, and profile management.
"""

from typing import List, Optional
from .models import Customer
from .database import Database
from .validators import validate_email, validate_non_empty_string


class CustomerService:
    """Service for managing restaurant customers."""

    def __init__(self, db: Database):
        self.db = db

    def register_customer(
        self, name: str, email: str = "", phone: str = ""
    ) -> Customer:
        """Register a new customer."""
        validate_non_empty_string(name, "Customer name")
        if email:
            validate_email(email)

        customer = Customer(name=name, email=email, phone=phone)
        return self.db.add_customer(customer)

    def get_customer(self, customer_id: str) -> Optional[Customer]:
        """Get a customer by ID."""
        return self.db.get_customer(customer_id)

    def get_all_customers(self) -> List[Customer]:
        """Get all customers."""
        return self.db.get_all_customers()

    def find_customer_by_email(self, email: str) -> Optional[Customer]:
        """Find a customer by email address."""
        for customer in self.db.get_all_customers():
            if customer.email.lower() == email.lower():
                return customer
        return None

    def find_customers_by_name(self, name: str) -> List[Customer]:
        """Find customers by name (partial match)."""
        name_lower = name.lower()
        return [
            c for c in self.db.get_all_customers() if name_lower in c.name.lower()
        ]

    def update_customer_info(
        self,
        customer_id: str,
        name: Optional[str] = None,
        email: Optional[str] = None,
        phone: Optional[str] = None,
    ) -> Customer:
        """Update customer profile information."""
        customer = self.db.get_customer(customer_id)
        if not customer:
            raise ValueError(f"Customer {customer_id} not found")

        if name is not None:
            validate_non_empty_string(name, "Customer name")
            customer.name = name

        if email is not None:
            if email:
                validate_email(email)
            customer.email = email

        if phone is not None:
            customer.phone = phone

        return self.db.update_customer(customer)

    def get_top_customers(self, limit: int = 10) -> List[Customer]:
        """Get top customers by total spent."""
        customers = self.db.get_all_customers()
        return sorted(customers, key=lambda c: c.total_spent, reverse=True)[:limit]

    def delete_customer(self, customer_id: str) -> bool:
        """Delete a customer."""
        return self.db.delete_customer(customer_id)

    # --- Loyalty Points Methods ---
    # TODO: Implement the following methods for the loyalty points feature:
    #
    # get_loyalty_balance(customer_id: str) -> int
    #   Returns the customer's current loyalty points balance.
    #
    # add_loyalty_points(customer_id: str, points: int) -> int
    #   Adds points to the customer's balance and earned history.
    #   Returns the new balance.
    #
    # redeem_loyalty_points(customer_id: str, points: int) -> float
    #   Redeems points for a dollar discount.
    #   Updates balance and redeemed history.
    #   Returns the dollar discount amount.
    #   Raises ValueError if insufficient balance.

"""
In-memory database and repository layer for the restaurant system.
Provides CRUD operations for all data models.
"""

from typing import Dict, List, Optional
from .models import Customer, MenuItem, Order, Payment, Reservation


class Database:
    """In-memory database that stores all restaurant data."""

    def __init__(self):
        self._customers: Dict[str, Customer] = {}
        self._menu_items: Dict[str, MenuItem] = {}
        self._orders: Dict[str, Order] = {}
        self._payments: Dict[str, Payment] = {}
        self._reservations: Dict[str, Reservation] = {}

    def clear(self):
        """Clear all data from the database."""
        self._customers.clear()
        self._menu_items.clear()
        self._orders.clear()
        self._payments.clear()
        self._reservations.clear()

    # --- Customer operations ---

    def add_customer(self, customer: Customer) -> Customer:
        self._customers[customer.id] = customer
        return customer

    def get_customer(self, customer_id: str) -> Optional[Customer]:
        return self._customers.get(customer_id)

    def get_all_customers(self) -> List[Customer]:
        return list(self._customers.values())

    def update_customer(self, customer: Customer) -> Customer:
        if customer.id not in self._customers:
            raise ValueError(f"Customer {customer.id} not found")
        self._customers[customer.id] = customer
        return customer

    def delete_customer(self, customer_id: str) -> bool:
        if customer_id in self._customers:
            del self._customers[customer_id]
            return True
        return False

    # --- Menu Item operations ---

    def add_menu_item(self, item: MenuItem) -> MenuItem:
        self._menu_items[item.id] = item
        return item

    def get_menu_item(self, item_id: str) -> Optional[MenuItem]:
        return self._menu_items.get(item_id)

    def get_all_menu_items(self) -> List[MenuItem]:
        return list(self._menu_items.values())

    def update_menu_item(self, item: MenuItem) -> MenuItem:
        if item.id not in self._menu_items:
            raise ValueError(f"Menu item {item.id} not found")
        self._menu_items[item.id] = item
        return item

    def delete_menu_item(self, item_id: str) -> bool:
        if item_id in self._menu_items:
            del self._menu_items[item_id]
            return True
        return False

    # --- Order operations ---

    def add_order(self, order: Order) -> Order:
        self._orders[order.id] = order
        return order

    def get_order(self, order_id: str) -> Optional[Order]:
        return self._orders.get(order_id)

    def get_all_orders(self) -> List[Order]:
        return list(self._orders.values())

    def get_orders_by_customer(self, customer_id: str) -> List[Order]:
        return [o for o in self._orders.values() if o.customer_id == customer_id]

    def update_order(self, order: Order) -> Order:
        if order.id not in self._orders:
            raise ValueError(f"Order {order.id} not found")
        self._orders[order.id] = order
        return order

    # --- Payment operations ---

    def add_payment(self, payment: Payment) -> Payment:
        self._payments[payment.id] = payment
        return payment

    def get_payment(self, payment_id: str) -> Optional[Payment]:
        return self._payments.get(payment_id)

    def get_payments_by_order(self, order_id: str) -> List[Payment]:
        return [p for p in self._payments.values() if p.order_id == order_id]

    # --- Reservation operations ---

    def add_reservation(self, reservation: Reservation) -> Reservation:
        self._reservations[reservation.id] = reservation
        return reservation

    def get_reservation(self, reservation_id: str) -> Optional[Reservation]:
        return self._reservations.get(reservation_id)

    def get_reservations_by_customer(self, customer_id: str) -> List[Reservation]:
        return [r for r in self._reservations.values() if r.customer_id == customer_id]

"""
Menu management service.
Handles menu item CRUD and availability.
"""

from typing import List, Optional
from .models import MenuItem, MenuCategory
from .database import Database
from .validators import validate_price, validate_non_empty_string
from . import config


class MenuService:
    """Service for managing the restaurant menu."""

    def __init__(self, db: Database):
        self.db = db

    def add_menu_item(
        self,
        name: str,
        description: str,
        price: float,
        category: MenuCategory,
        prep_time_minutes: int = 15,
        calories: int = 0,
    ) -> MenuItem:
        """Add a new item to the menu."""
        validate_non_empty_string(name, "Menu item name")
        validate_price(price)

        item = MenuItem(
            name=name,
            description=description,
            price=price,
            category=category,
            prep_time_minutes=prep_time_minutes,
            calories=calories,
        )
        return self.db.add_menu_item(item)

    def get_menu_item(self, item_id: str) -> Optional[MenuItem]:
        """Get a menu item by ID."""
        return self.db.get_menu_item(item_id)

    def get_full_menu(self) -> List[MenuItem]:
        """Get all menu items."""
        return self.db.get_all_menu_items()

    def get_available_items(self) -> List[MenuItem]:
        """Get only available menu items."""
        return [item for item in self.db.get_all_menu_items() if item.is_available]

    def get_items_by_category(self, category: MenuCategory) -> List[MenuItem]:
        """Get menu items filtered by category."""
        return [
            item
            for item in self.db.get_all_menu_items()
            if item.category == category and item.is_available
        ]

    def update_price(self, item_id: str, new_price: float) -> MenuItem:
        """Update the price of a menu item."""
        validate_price(new_price)
        item = self.db.get_menu_item(item_id)
        if not item:
            raise ValueError(f"Menu item {item_id} not found")
        item.price = new_price
        return self.db.update_menu_item(item)

    def toggle_availability(self, item_id: str) -> MenuItem:
        """Toggle a menu item's availability."""
        item = self.db.get_menu_item(item_id)
        if not item:
            raise ValueError(f"Menu item {item_id} not found")
        item.is_available = not item.is_available
        return self.db.update_menu_item(item)

    def remove_menu_item(self, item_id: str) -> bool:
        """Remove a menu item from the menu."""
        return self.db.delete_menu_item(item_id)

    def search_menu(self, query: str) -> List[MenuItem]:
        """Search menu items by name or description."""
        query_lower = query.lower()
        return [
            item
            for item in self.db.get_all_menu_items()
            if query_lower in item.name.lower()
            or query_lower in item.description.lower()
        ]

    def get_items_under_price(self, max_price: float) -> List[MenuItem]:
        """Get available menu items under a certain price."""
        return [
            item
            for item in self.db.get_all_menu_items()
            if item.is_available and item.price <= max_price
        ]

"""
Data models for the restaurant management system.
"""

from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import List, Optional
import uuid


class OrderStatus(Enum):
    PENDING = "pending"
    CONFIRMED = "confirmed"
    PREPARING = "preparing"
    READY = "ready"
    DELIVERED = "delivered"
    CANCELLED = "cancelled"


class PaymentMethod(Enum):
    CASH = "cash"
    CREDIT_CARD = "credit_card"
    DEBIT_CARD = "debit_card"
    LOYALTY_POINTS = "loyalty_points"


class MenuCategory(Enum):
    APPETIZER = "appetizer"
    MAIN_COURSE = "main_course"
    DESSERT = "dessert"
    BEVERAGE = "beverage"
    SIDE = "side"


@dataclass
class MenuItem:
    id: str = ""
    name: str = ""
    description: str = ""
    price: float = 0.0
    category: MenuCategory = MenuCategory.MAIN_COURSE
    is_available: bool = True
    prep_time_minutes: int = 15
    calories: int = 0

    def __post_init__(self):
        if not self.id:
            self.id = str(uuid.uuid4())[:8]


@dataclass
class Customer:
    id: str = ""
    name: str = ""
    email: str = ""
    phone: str = ""
    created_at: datetime = None
    total_spent: float = 0.0
    order_count: int = 0
    loyalty_points: int = 0
    loyalty_points_earned: int = 0
    loyalty_points_redeemed: int = 0

    def __post_init__(self):
        if not self.id:
            self.id = str(uuid.uuid4())[:8]
        if self.created_at is None:
            self.created_at = datetime.now()


@dataclass
class OrderItem:
    menu_item_id: str = ""
    menu_item_name: str = ""
    quantity: int = 1
    unit_price: float = 0.0
    special_instructions: str = ""

    @property
    def subtotal(self) -> float:
        return self.unit_price * self.quantity


@dataclass
class Order:
    id: str = ""
    customer_id: str = ""
    items: List[OrderItem] = field(default_factory=list)
    status: OrderStatus = OrderStatus.PENDING
    created_at: datetime = None
    total: float = 0.0
    tax: float = 0.0
    tip: float = 0.0
    discount: float = 0.0
    payment_method: Optional[PaymentMethod] = None
    is_paid: bool = False
    notes: str = ""
    loyalty_points_earned: int = 0

    def __post_init__(self):
        if not self.id:
            self.id = str(uuid.uuid4())[:8]
        if self.created_at is None:
            self.created_at = datetime.now()

    @property
    def subtotal(self) -> float:
        return sum(item.subtotal for item in self.items)

    @property
    def grand_total(self) -> float:
        return self.subtotal + self.tax + self.tip - self.discount


@dataclass
class Payment:
    id: str = ""
    order_id: str = ""
    amount: float = 0.0
    method: PaymentMethod = PaymentMethod.CASH
    processed_at: datetime = None
    is_successful: bool = False

    def __post_init__(self):
        if not self.id:
            self.id = str(uuid.uuid4())[:8]
        if self.processed_at is None:
            self.processed_at = datetime.now()


@dataclass
class Reservation:
    id: str = ""
    customer_id: str = ""
    party_size: int = 2
    reservation_time: datetime = None
    notes: str = ""
    is_confirmed: bool = False

    def __post_init__(self):
        if not self.id:
            self.id = str(uuid.uuid4())[:8]

"""
Order processing service.
Handles order creation, status updates, and order management.
"""

import math
from typing import List, Optional, Tuple
from .models import Order, OrderItem, OrderStatus, MenuCategory
from .database import Database
from .config import TAX_RATE, MIN_ORDER_AMOUNT, MAX_ORDER_ITEMS


class OrderService:
    """Service for managing restaurant orders."""

    def __init__(self, db: Database, customer_service=None):
        self.db = db
        self.customer_service = customer_service

    def create_order(self, customer_id: str) -> Order:
        """Create a new empty order for a customer."""
        customer = self.db.get_customer(customer_id)
        if not customer:
            raise ValueError(f"Customer {customer_id} not found")

        order = Order(customer_id=customer_id)
        return self.db.add_order(order)

    def add_item_to_order(
        self,
        order_id: str,
        menu_item_id: str,
        quantity: int = 1,
        special_instructions: str = "",
    ) -> Order:
        """Add a menu item to an existing order."""
        order = self.db.get_order(order_id)
        if not order:
            raise ValueError(f"Order {order_id} not found")

        if order.status != OrderStatus.PENDING:
            raise ValueError("Cannot modify a non-pending order")

        menu_item = self.db.get_menu_item(menu_item_id)
        if not menu_item:
            raise ValueError(f"Menu item {menu_item_id} not found")

        if not menu_item.is_available:
            raise ValueError(f"Menu item {menu_item.name} is not available")

        if quantity < 1:
            raise ValueError("Quantity must be at least 1")

        if len(order.items) >= MAX_ORDER_ITEMS:
            raise ValueError(f"Order cannot have more than {MAX_ORDER_ITEMS} items")

        order_item = OrderItem(
            menu_item_id=menu_item_id,
            menu_item_name=menu_item.name,
            quantity=quantity,
            unit_price=menu_item.price,
            special_instructions=special_instructions,
        )
        order.items.append(order_item)
        self._recalculate_order(order)
        return self.db.update_order(order)

    def remove_item_from_order(self, order_id: str, item_index: int) -> Order:
        """Remove an item from an order by index."""
        order = self.db.get_order(order_id)
        if not order:
            raise ValueError(f"Order {order_id} not found")

        if order.status != OrderStatus.PENDING:
            raise ValueError("Cannot modify a non-pending order")

        if item_index < 0 or item_index >= len(order.items):
            raise ValueError("Invalid item index")

        order.items.pop(item_index)
        self._recalculate_order(order)
        return self.db.update_order(order)

    def place_order(self, order_id: str) -> Order:
        """Finalize and place an order."""
        order = self.db.get_order(order_id)
        if not order:
            raise ValueError(f"Order {order_id} not found")

        if order.status != OrderStatus.PENDING:
            raise ValueError("Order is not in pending status")

        if not order.items:
            raise ValueError("Cannot place an empty order")

        if order.subtotal < MIN_ORDER_AMOUNT:
            raise ValueError(
                f"Order total must be at least ${MIN_ORDER_AMOUNT:.2f}"
            )

        order.status = OrderStatus.CONFIRMED
        self._recalculate_order(order)

        # Update customer stats
        customer = self.db.get_customer(order.customer_id)
        if customer:
            customer.total_spent += order.grand_total
            customer.order_count += 1
            self.db.update_customer(customer)

        # TODO: Award loyalty points after successful order
        # Calculate points based on amount paid (grand_total) and award them
        # using customer_service.add_loyalty_points()
        # Store earned points on the order's loyalty_points_earned field

        return self.db.update_order(order)

    def update_order_status(self, order_id: str, new_status: OrderStatus) -> Order:
        """Update the status of an order."""
        order = self.db.get_order(order_id)
        if not order:
            raise ValueError(f"Order {order_id} not found")

        valid_transitions = {
            OrderStatus.PENDING: [OrderStatus.CONFIRMED, OrderStatus.CANCELLED],
            OrderStatus.CONFIRMED: [OrderStatus.PREPARING, OrderStatus.CANCELLED],
            OrderStatus.PREPARING: [OrderStatus.READY, OrderStatus.CANCELLED],
            OrderStatus.READY: [OrderStatus.DELIVERED],
            OrderStatus.DELIVERED: [],
            OrderStatus.CANCELLED: [],
        }

        if new_status not in valid_transitions.get(order.status, []):
            raise ValueError(
                f"Cannot transition from {order.status.value} to {new_status.value}"
            )

        order.status = new_status
        return self.db.update_order(order)

    def apply_discount(self, order_id: str, discount_amount: float) -> Order:
        """Apply a discount to an order."""
        order = self.db.get_order(order_id)
        if not order:
            raise ValueError(f"Order {order_id} not found")

        if discount_amount < 0:
            raise ValueError("Discount cannot be negative")

        if discount_amount > order.subtotal:
            raise ValueError("Discount cannot exceed order subtotal")

        order.discount = discount_amount
        self._recalculate_order(order)
        return self.db.update_order(order)

    def get_order(self, order_id: str) -> Optional[Order]:
        """Get an order by ID."""
        return self.db.get_order(order_id)

    def get_customer_orders(self, customer_id: str) -> List[Order]:
        """Get all orders for a customer."""
        return self.db.get_orders_by_customer(customer_id)

    def _recalculate_order(self, order: Order):
        """Recalculate order totals."""
        order.total = order.subtotal
        order.tax = round(order.subtotal * TAX_RATE, 2)

"""
Payment processing service.
Handles payment collection and transaction management.
"""

from typing import Optional
from .models import Order, Payment, PaymentMethod, OrderStatus
from .database import Database


class PaymentService:
    """Service for processing restaurant payments."""

    def __init__(self, db: Database, customer_service=None):
        self.db = db
        self.customer_service = customer_service

    def process_payment(
        self, order_id: str, method: PaymentMethod, amount: Optional[float] = None
    ) -> Payment:
        """Process a payment for an order."""
        order = self.db.get_order(order_id)
        if not order:
            raise ValueError(f"Order {order_id} not found")

        if order.is_paid:
            raise ValueError("Order is already paid")

        if order.status == OrderStatus.CANCELLED:
            raise ValueError("Cannot pay for a cancelled order")

        payment_amount = amount if amount is not None else order.grand_total

        if payment_amount <= 0:
            raise ValueError("Payment amount must be positive")

        if payment_amount < order.grand_total:
            raise ValueError("Payment amount is less than order total")

        payment = Payment(
            order_id=order_id,
            amount=payment_amount,
            method=method,
            is_successful=True,
        )

        order.is_paid = True
        order.payment_method = method
        self.db.update_order(order)

        return self.db.add_payment(payment)

    def get_payment(self, payment_id: str) -> Optional[Payment]:
        """Get a payment by ID."""
        return self.db.get_payment(payment_id)

    def get_payments_for_order(self, order_id: str):
        """Get all payments for an order."""
        return self.db.get_payments_by_order(order_id)

    def calculate_change(self, order_id: str, amount_tendered: float) -> float:
        """Calculate change for a cash payment."""
        order = self.db.get_order(order_id)
        if not order:
            raise ValueError(f"Order {order_id} not found")

        change = amount_tendered - order.grand_total
        if change < 0:
            raise ValueError("Insufficient payment amount")

        return round(change, 2)

    def add_tip(self, order_id: str, tip_amount: float) -> Order:
        """Add a tip to an order."""
        order = self.db.get_order(order_id)
        if not order:
            raise ValueError(f"Order {order_id} not found")

        if tip_amount < 0:
            raise ValueError("Tip cannot be negative")

        order.tip = tip_amount
        return self.db.update_order(order)

